pa_indicators.script:
(function collectIndicator(indicator) {
    var gr = new GlideRecord('incident');
    gr.addQuery('priority', 'IN', '1,2');
    gr.addQuery('state', 6); // Resolved
    gr.addQuery('resolved_at', '>=', gs.daysAgoStart(1));
    gr.addQuery('resolved_at', '<=', gs.daysAgoEnd(0));
    gr.query();

    var totalSeconds = 0;
    var count = 0;

    while (gr.next()) {
        var opened  = new GlideDateTime(gr.opened_at.toString());
        var resolved = new GlideDateTime(gr.resolved_at.toString());
        var diff = GlideDateTime.subtract(opened, resolved);
        totalSeconds += diff.getNumericValue() / 1000;
        count++;
    }

    if (count > 0) {
        return Math.round(totalSeconds / count / 60); // Return in minutes
    }
    return 0;
})(indicator);
